import androidx.security.crypto.EncryptedSharedPreferences
import androidx.security.crypto.MasterKey

class SessionTokenStore(private val context: Context) {

    private val masterKey = MasterKey.Builder(context)
        .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
        .build()

    private val prefs: SharedPreferences = EncryptedSharedPreferences.create(
        context,
        "claude_session_prefs",     // file name — keep it non-descriptive
        masterKey,
        EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
        EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
    )

    fun saveSessionToken(token: String) {
        prefs.edit().putString("session_token", token).apply()
    }

    fun getSessionToken(): String? = prefs.getString("session_token", null)

    fun clearSessionToken() {
        prefs.edit().remove("session_token").apply()
    }
}

import android.security.keystore.KeyGenParameterSpec
import android.security.keystore.KeyProperties
import java.security.KeyStore
import javax.crypto.Cipher
import javax.crypto.KeyGenerator
import javax.crypto.spec.GCMParameterSpec

object KeystoreHelper {

    private const val KEY_ALIAS = "claude_refresh_key"
    private const val PROVIDER    = "AndroidKeyStore"
    private const val ALGORITHM   = KeyProperties.KEY_ALGORITHM_AES
    private const val BLOCK_MODE  = KeyProperties.BLOCK_MODE_GCM
    private const val PADDING     = KeyProperties.ENCRYPTION_PADDING_NONE
    private const val GCM_TAG_LEN = 128

    fun getOrCreateKey(): javax.crypto.SecretKey {
        val keyStore = KeyStore.getInstance(PROVIDER).apply { load(null) }
        keyStore.getKey(KEY_ALIAS, null)?.let { return it as javax.crypto.SecretKey }

        val keyGenerator = KeyGenerator.getInstance(ALGORITHM, PROVIDER)
        keyGenerator.init(
            KeyGenParameterSpec.Builder(
                KEY_ALIAS,
                KeyProperties.PURPOSE_ENCRYPT or KeyProperties.PURPOSE_DECRYPT
            )
                .setBlockModes(BLOCK_MODE)
                .setEncryptionPaddings(PADDING)
                .setKeySize(256)
                .setUserAuthenticationRequired(true)       // requires biometric or PIN
                .setUserAuthenticationParameters(           // API 30+
                    0,  // 0 = each use requires fresh auth (not time-based)
                    KeyProperties.AUTH_BIOMETRIC_STRONG or KeyProperties.AUTH_DEVICE_CREDENTIAL
                )
                .build()
        )
        return keyGenerator.generateKey()
    }

    fun encrypt(plaintext: String, key: javax.crypto.SecretKey): Pair<ByteArray, ByteArray> {
        val cipher = Cipher.getInstance("$ALGORITHM/$BLOCK_MODE/$PADDING")
        cipher.init(Cipher.ENCRYPT_MODE, key)
        val iv         = cipher.iv
        val ciphertext = cipher.doFinal(plaintext.toByteArray(Charsets.UTF_8))
        return Pair(iv, ciphertext)
    }

    fun decrypt(iv: ByteArray, ciphertext: ByteArray, key: javax.crypto.SecretKey): String {
        val cipher = Cipher.getInstance("$ALGORITHM/$BLOCK_MODE/$PADDING")
        cipher.init(Cipher.DECRYPT_MODE, key, GCMParameterSpec(GCM_TAG_LEN, iv))
        return String(cipher.doFinal(ciphertext), Charsets.UTF_8)
    }
}

import android.util.Base64
import javax.crypto.KeyGenerator as JCEKeyGenerator

class EnvelopeStore(context: Context, private val prefs: SharedPreferences) {

    fun storeRefreshToken(token: String, kek: javax.crypto.SecretKey) {
        // 1. Generate a fresh DEK for this token
        val dek = JCEKeyGenerator.getInstance("AES").apply { init(256) }.generateKey()

        // 2. Encrypt the token with the DEK
        val (iv, ciphertext) = KeystoreHelper.encrypt(token, dek)

        // 3. Encrypt the DEK with the Keystore KEK
        val (kekIv, encryptedDek) = KeystoreHelper.encrypt(
            Base64.encodeToString(dek.encoded, Base64.NO_WRAP),
            kek
        )

        // 4. Store ciphertext + IV + encrypted DEK + DEK IV in prefs
        prefs.edit()
            .putString("enc_token", Base64.encodeToString(ciphertext, Base64.NO_WRAP))
            .putString("token_iv",  Base64.encodeToString(iv, Base64.NO_WRAP))
            .putString("enc_dek",   Base64.encodeToString(encryptedDek, Base64.NO_WRAP))
            .putString("dek_iv",    Base64.encodeToString(kekIv, Base64.NO_WRAP))
            .apply()
    }

    fun loadRefreshToken(kek: javax.crypto.SecretKey): String? {
        val encToken   = prefs.getString("enc_token", null) ?: return null
        val tokenIv    = prefs.getString("token_iv",  null) ?: return null
        val encDek     = prefs.getString("enc_dek",   null) ?: return null
        val dekIv      = prefs.getString("dek_iv",    null) ?: return null

        // 1. Decrypt DEK with Keystore KEK (requires auth if gate enabled)
        val dekBytes = Base64.decode(
            KeystoreHelper.decrypt(
                Base64.decode(dekIv, Base64.NO_WRAP),
                Base64.decode(encDek, Base64.NO_WRAP),
                kek
            ), Base64.NO_WRAP
        )
        val dek = javax.crypto.spec.SecretKeySpec(dekBytes, "AES")

        // 2. Decrypt payload with DEK
        return KeystoreHelper.decrypt(
            Base64.decode(tokenIv, Base64.NO_WRAP),
            Base64.decode(encToken, Base64.NO_WRAP),
            dek
        )
    }
}

import androidx.biometric.BiometricManager
import androidx.biometric.BiometricPrompt
import androidx.core.content.ContextCompat
import androidx.fragment.app.FragmentActivity
import javax.crypto.Cipher
import javax.crypto.spec.GCMParameterSpec

class BiometricDecryptor(
    private val activity: FragmentActivity,
    private val onDecrypted: (String) -> Unit,
    private val onError: (String) -> Unit,
    private val onKeyInvalidated: () -> Unit
) {

    fun decryptWithBiometric(
        iv: ByteArray,
        ciphertext: ByteArray,
        key: javax.crypto.SecretKey
    ) {
        val cipher = Cipher.getInstance("AES/GCM/NoPadding")
        try {
            cipher.init(Cipher.DECRYPT_MODE, key, GCMParameterSpec(128, iv))
        } catch (e: android.security.keystore.KeyPermanentlyInvalidatedException) {
            // Biometric enrollment changed — key cannot be recovered
            onKeyInvalidated()
            return
        }
        // UserNotAuthenticatedException is NOT thrown here; it's thrown inside
        // BiometricPrompt if auth is missing. We pass the Cipher proactively.

        val promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle("Confirm identity")
            .setSubtitle("Authenticate to access stored credentials")
            .setAllowedAuthenticators(
                BiometricManager.Authenticators.BIOMETRIC_STRONG or
                BiometricManager.Authenticators.DEVICE_CREDENTIAL
            )
            .build()

        BiometricPrompt(
            activity,
            ContextCompat.getMainExecutor(activity),
            object : BiometricPrompt.AuthenticationCallback() {
                override fun onAuthenticationSucceeded(
                    result: BiometricPrompt.AuthenticationResult
                ) {
                    // result.cryptoObject?.cipher is the auth-unlocked Cipher
                    val authenticatedCipher = result.cryptoObject!!.cipher!!
                    val plaintext = String(
                        authenticatedCipher.doFinal(ciphertext),
                        Charsets.UTF_8
                    )
                    onDecrypted(plaintext)
                }

                override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                    onError(errString.toString())
                }

                override fun onAuthenticationFailed() {
                    // Single failed attempt; the prompt stays visible — do nothing
                }
            }
        ).authenticate(promptInfo, BiometricPrompt.CryptoObject(cipher))
    }
}

import android.util.Base64
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import java.security.KeyStore

class SecureTokenRepository(
    private val sessionStore: SessionTokenStore,
    private val envelopeStore: EnvelopeStore
) {

    suspend fun saveSessionToken(token: String) = withContext(Dispatchers.IO) {
        sessionStore.saveSessionToken(token)
    }

    suspend fun loadSessionToken(): String? = withContext(Dispatchers.IO) {
        sessionStore.getSessionToken()
    }

    suspend fun loadRefreshToken(kek: javax.crypto.SecretKey): Result<String?> =
        withContext(Dispatchers.IO) {
            runCatching {
                envelopeStore.loadRefreshToken(kek)
            }.recoverCatching { e ->
                when (e) {
                    is android.security.keystore.KeyPermanentlyInvalidatedException -> {
                        // User changed biometric enrollment — delete stale key + ciphertext
                        invalidateStoredSecrets()
                        null   // caller should redirect to login flow
                    }
                    else -> throw e
                }
            }
        }

    private fun invalidateStoredSecrets() {
        sessionStore.clearSessionToken()
        val keyStore = KeyStore.getInstance("AndroidKeyStore").apply { load(null) }
        keyStore.deleteEntry("claude_refresh_key")
    }
}

